import {
  ChangeDetectionStrategy,
  Component,
  DestroyRef,
  ElementRef,
  Signal,
  computed,
  inject,
  input,
  model,
  output,
  viewChild,
} from '@angular/core';
import { ControlValueAccessor } from '@angular/forms';
import { injectFormControl } from '../../utils/form-control';
import { mergeClasses } from '../../utils/merge-classes';
import {
  RADIO_GROUP_CTX,
  type RadioColor,
  type RadioGroupContext,
  type RadioItemRef,
  type RadioSize,
  type RadioVariant,
} from './radio.tokens';
import {
  radioCardVariants,
  radioIndicatorVariants,
  radioVariants,
} from './radio.variants';

let _radioIdCounter = 0;

@Component({
  selector: 'n-radio',
  standalone: true,
  template: `
    <label [class]="rootClasses()" data-slot="root" [for]="radioId()">
      <span [class]="wrapperClasses()" data-slot="control-wrapper">
        <input
          #control
          type="radio"
          [id]="radioId()"
          [name]="resolvedName()"
          [value]="stringValue()"
          [checked]="isChecked()"
          [disabled]="isDisabled()"
          [required]="isRequired()"
          [attr.tabindex]="tabIndex()"
          [attr.aria-label]="nLabel() ? null : nAriaLabel() || null"
          [attr.aria-describedby]="describedBy()"
          [attr.aria-invalid]="hasError() ? true : null"
          [attr.aria-required]="isRequired() ? true : null"
          data-slot="control"
          [class]="controlClasses()"
          (change)="handleChange()"
          (focus)="handleFocus()"
          (blur)="handleBlur($event)"
          (keydown)="handleKeydown($event)"
        />
        @if (isChecked()) {
          <span data-slot="indicator" [class]="indicatorClasses()" aria-hidden="true"></span>
        }
      </span>

      <span class="flex flex-col gap-0.5">
        @if (nLabel()) {
          <span [class]="labelClasses()" data-slot="label">
            {{ nLabel() }}
            @if (isRequired() && !inGroup()) {
              <span class="ml-0.5 text-destructive" aria-hidden="true">*</span>
            }
          </span>
        }
        <span data-slot="description" [class]="descriptionClasses()">
          @if (nDescription()) {
            {{ nDescription() }}
          }
          <ng-content select="[slot=description]" />
        </span>
      </span>
    </label>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents' },
})
export class RadioComponent<T = string> implements ControlValueAccessor, RadioItemRef {
  readonly nValue       = input.required<T>();
  readonly nLabel       = input<string>('');
  readonly nDescription = input<string>('');
  readonly nDisabled    = input<boolean>(false);
  readonly nRequired    = input<boolean>(false);
  readonly nClass       = input<string>('');
  readonly nAriaLabel   = input<string>('');
  readonly nId          = input<string>('');
  readonly nName        = input<string>('');
  readonly nSize        = input<RadioSize | null>(null);
  readonly nVariant     = input<RadioVariant | null>(null);
  readonly nColor       = input<RadioColor | null>(null);
  readonly nChecked     = model<boolean>(false);

  readonly nChange = output<T>();
  readonly nBlur   = output<FocusEvent>();
  readonly nFocus  = output<FocusEvent>();

  private readonly _group: RadioGroupContext | null = inject(RADIO_GROUP_CTX, { optional: true });
  private readonly _form     = injectFormControl<T | null>(this);
  private readonly _staticId = `n-radio-${++_radioIdCounter}`;
  private readonly _destroyRef = inject(DestroyRef);
  private readonly _hostEl   = inject(ElementRef<HTMLElement>);
  private readonly _controlRef = viewChild<ElementRef<HTMLInputElement>>('control');

  protected readonly inGroup = computed(() => this._group !== null);

  protected readonly resolvedSize: Signal<RadioSize> = computed(
    () => this.nSize() ?? this._group?.size() ?? 'default',
  );
  protected readonly resolvedVariant: Signal<RadioVariant> = computed(
    () => this.nVariant() ?? this._group?.variant() ?? 'default',
  );
  protected readonly resolvedColor: Signal<RadioColor> = computed(
    () => this.nColor() ?? this._group?.color() ?? 'default',
  );

  protected readonly isDisabled = computed(
    () => this.nDisabled() || (this._group?.disabled() ?? false) || (this._group?.loading() ?? false) || this._form.disabledByForm(),
  );
  protected readonly isRequired = computed(
    () => this.nRequired() || (this._group?.required() ?? false),
  );
  protected readonly hasError = computed(
    () => (this._group?.hasError() ?? false) || (this._form.controlInvalid() && this._form.controlTouched()),
  );

  protected readonly isChecked = computed(() => {
    if (this._group) {
      return this._group.value() === this.nValue();
    }
    return this.nChecked();
  });

  protected readonly radioId = computed(() => this.nId() || this._staticId);
  protected readonly errorId = computed(() => `${this.radioId()}-error`);
  protected readonly hintId  = computed(() => `${this.radioId()}-hint`);

  protected readonly resolvedName = computed(
    () => this.nName() || this._group?.name() || `n-radio-name-${this._staticId}`,
  );

  protected readonly describedBy = computed(() => {
    if (this.hasError()) return this.errorId();
    return null;
  });

  protected readonly tabIndex = computed(() => {
    if (this.isDisabled()) return -1;
    if (!this._group) return 0;
    if (this.isChecked()) return 0;
    const anyChecked = this._group.value() !== null && this._group.value() !== undefined;
    if (!anyChecked && this._group.isFirstEnabled(this)) return 0;
    return -1;
  });

  protected readonly wrapperClasses = computed(() =>
    mergeClasses(
      'relative inline-flex items-center justify-center',
      this.resolvedVariant() === 'card' && 'absolute right-3 top-1/2 -translate-y-1/2',
    ),
  );

  protected readonly controlClasses = computed(() =>
    radioVariants({ nSize: this.resolvedSize(), nColor: this.resolvedColor() }),
  );

  protected readonly indicatorClasses = computed(() =>
    radioIndicatorVariants({ nSize: this.resolvedSize(), nColor: this.resolvedColor() }),
  );

  protected readonly rootClasses = computed(() => {
    if (this.resolvedVariant() === 'card') {
      return mergeClasses(
        radioCardVariants({ nColor: this.resolvedColor() }),
        'relative pr-12',
        this.nClass(),
      );
    }
    return mergeClasses(
      'inline-flex items-start gap-2 cursor-pointer select-none',
      this.isDisabled() && 'cursor-not-allowed opacity-50',
      this.nClass(),
    );
  });

  protected readonly labelClasses = computed(() =>
    mergeClasses('text-sm font-medium leading-none cursor-pointer'),
  );

  protected readonly descriptionClasses = computed(() =>
    mergeClasses('text-xs text-muted-foreground'),
  );

  protected readonly stringValue = computed(() => {
    const v = this.nValue();
    return typeof v === 'string' ? v : JSON.stringify(v);
  });

  constructor() {
    this._group?.register(this);
    this._destroyRef.onDestroy(() => this._group?.unregister(this));
  }

  value(): unknown {
    return this.nValue();
  }

  disabled(): boolean {
    return this.isDisabled();
  }

  focus(): void {
    const el = this._controlRef()?.nativeElement ?? this._hostEl.nativeElement.querySelector('input');
    (el as HTMLInputElement | null)?.focus();
  }

  protected handleChange(): void {
    if (this._group) {
      this._group.select(this.nValue());
    } else {
      this.nChecked.set(true);
      this._form.notifyChange(this.nValue());
    }
    this.nChange.emit(this.nValue());
  }

  protected handleFocus(): void {
    this.nFocus.emit(new FocusEvent('focus'));
  }

  protected handleBlur(event: FocusEvent): void {
    if (this._group) {
      this._group.notifyTouched();
    } else {
      this._form.notifyTouched();
    }
    this.nBlur.emit(event);
  }

  protected handleKeydown(event: KeyboardEvent): void {
    if (!this._group) return;
    switch (event.key) {
      case 'ArrowDown':
      case 'ArrowRight':
        event.preventDefault();
        this._group.focusNext(this);
        break;
      case 'ArrowUp':
      case 'ArrowLeft':
        event.preventDefault();
        this._group.focusPrev(this);
        break;
    }
  }

  writeValue(value: T | null | undefined): void {
    if (this._group) return;
    this.nChecked.set(value === this.nValue());
  }

  registerOnChange(fn: (v: T | null) => void): void {
    this._form.setOnChange(fn);
  }

  registerOnTouched(fn: () => void): void {
    this._form.setOnTouched(fn);
  }

  setDisabledState(isDisabled: boolean): void {
    this._form.setDisabledByForm(isDisabled);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  model,
  output,
  signal,
} from '@angular/core';
import { ControlValueAccessor } from '@angular/forms';
import { injectFormControl } from '../../utils/form-control';
import { mergeClasses } from '../../utils/merge-classes';
import { SkeletonComponent } from '../skeleton/skeleton.component';
import {
  RADIO_GROUP_CTX,
  type RadioColor,
  type RadioGroupContext,
  type RadioItemRef,
  type RadioSize,
  type RadioVariant,
} from './radio.tokens';

let _radioGroupIdCounter = 0;

@Component({
  selector: 'n-radio-group',
  standalone: true,
  imports: [SkeletonComponent],
  template: `
    <div [class]="wrapperClasses()" data-slot="root">
      @if (nLabel()) {
        <span [id]="labelId()" [class]="labelClasses()" data-slot="label">
          {{ nLabel() }}
          @if (nRequired()) {
            <span class="ml-0.5 text-destructive" aria-hidden="true">*</span>
          }
        </span>
      }

      <div
        role="radiogroup"
        [attr.aria-labelledby]="nLabel() ? labelId() : null"
        [attr.aria-label]="nLabel() ? null : nAriaLabel() || null"
        [attr.aria-describedby]="describedBy()"
        [attr.aria-required]="nRequired() ? true : null"
        [attr.aria-invalid]="hasError() ? true : null"
        [attr.aria-busy]="nLoading() ? true : null"
        [attr.aria-disabled]="isDisabled() ? true : null"
        [class]="controlWrapperClasses()"
        data-slot="control-wrapper"
      >
        @if (nLoading()) {
          @for (i of skeletonRows(); track i) {
            <n-skeleton class="h-5 w-40" />
          }
        } @else {
          <ng-content />
        }
      </div>

      @if (hasError()) {
        <p [id]="errorId()" class="mt-1 text-xs text-destructive" role="alert" data-slot="error">
          {{ nError() }}
        </p>
      }

      @if (nHint() && !hasError()) {
        <p [id]="hintId()" class="mt-1 text-xs text-muted-foreground" data-slot="hint">
          {{ nHint() }}
        </p>
      }
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents' },
  providers: [
    {
      provide: RADIO_GROUP_CTX,
      useFactory: (group: RadioGroupComponent) => group.ctx,
      deps: [forwardRef(() => RadioGroupComponent)],
    },
  ],
})
export class RadioGroupComponent<T = string> implements ControlValueAccessor {
  readonly nValue       = model<T | null>(null);
  readonly nName        = input<string>('');
  readonly nLabel       = input<string>('');
  readonly nDisabled    = input<boolean>(false);
  readonly nRequired    = input<boolean>(false);
  readonly nLoading     = input<boolean>(false);
  readonly nError       = input<string | null>(null);
  readonly nHint        = input<string | null>(null);
  readonly nClass       = input<string>('');
  readonly nAriaLabel   = input<string>('');
  readonly nId          = input<string>('');
  readonly nOrientation = input<'vertical' | 'horizontal'>('vertical');
  readonly nSize        = input<RadioSize>('default');
  readonly nVariant     = input<RadioVariant>('default');
  readonly nColor       = input<RadioColor>('default');
  readonly nSkeletonRows = input<number>(3);

  readonly nChange = output<T | null>();

  private readonly _form     = injectFormControl<T | null>(this);
  private readonly _staticId = `n-radio-group-${++_radioGroupIdCounter}`;
  private readonly _items    = new Set<RadioItemRef>();
  private readonly _orderedItems = signal<RadioItemRef[]>([]);

  protected readonly isDisabled = computed(() => this.nDisabled() || this._form.disabledByForm());
  protected readonly hasError   = computed(
    () => !!this.nError() || (this._form.controlInvalid() && this._form.controlTouched()),
  );

  protected readonly groupId  = computed(() => this.nId() || this._staticId);
  protected readonly labelId  = computed(() => `${this.groupId()}-label`);
  protected readonly errorId  = computed(() => `${this.groupId()}-error`);
  protected readonly hintId   = computed(() => `${this.groupId()}-hint`);
  protected readonly resolvedName = computed(() => this.nName() || this.groupId());

  protected readonly describedBy = computed(() => {
    if (this.hasError()) return this.errorId();
    if (this.nHint()) return this.hintId();
    return null;
  });

  protected readonly skeletonRows = computed(() =>
    Array.from({ length: Math.max(1, this.nSkeletonRows()) }, (_, i) => i),
  );

  protected readonly wrapperClasses = computed(() =>
    mergeClasses('flex flex-col', this.nClass()),
  );

  protected readonly labelClasses = computed(() =>
    mergeClasses(
      'block text-sm font-medium leading-none mb-2',
      this.isDisabled() && 'opacity-50',
    ),
  );

  protected readonly controlWrapperClasses = computed(() =>
    mergeClasses(
      'flex',
      this.nOrientation() === 'horizontal' ? 'flex-row flex-wrap gap-4' : 'flex-col gap-2',
      this.nLoading() && 'pointer-events-none',
    ),
  );

  readonly ctx: RadioGroupContext = {
    name:     computed(() => this.resolvedName()),
    value:    computed<unknown>(() => this.nValue()),
    disabled: computed(() => this.isDisabled()),
    required: computed(() => this.nRequired()),
    hasError: computed(() => this.hasError()),
    size:     computed(() => this.nSize()),
    variant:  computed(() => this.nVariant()),
    color:    computed(() => this.nColor()),
    loading:  computed(() => this.nLoading()),
    select:   (v) => this.handleSelect(v as T),
    notifyTouched: () => this._form.notifyTouched(),
    register:   (item) => this.registerItem(item),
    unregister: (item) => this.unregisterItem(item),
    focusNext:  (current) => this.moveFocus(current, 1),
    focusPrev:  (current) => this.moveFocus(current, -1),
    isFirstEnabled: (item) => {
      const enabled = this._orderedItems().filter((i) => !i.disabled());
      return enabled[0] === item;
    },
  };

  private registerItem(item: RadioItemRef): void {
    this._items.add(item);
    this._orderedItems.set(Array.from(this._items));
  }

  private unregisterItem(item: RadioItemRef): void {
    this._items.delete(item);
    this._orderedItems.set(Array.from(this._items));
  }

  private moveFocus(current: RadioItemRef, dir: 1 | -1): void {
    const items = this._orderedItems().filter((i) => !i.disabled());
    if (items.length === 0) return;
    const idx = items.indexOf(current);
    if (idx < 0) {
      items[0].focus();
      return;
    }
    const next = items[(idx + dir + items.length) % items.length];
    next.focus();
    this.handleSelect(next.value() as T);
  }

  private handleSelect(value: T): void {
    this.nValue.set(value);
    this._form.notifyChange(value);
    this.nChange.emit(value);
  }

  writeValue(value: T | null | undefined): void {
    this.nValue.set(value ?? null);
  }

  registerOnChange(fn: (v: T | null) => void): void {
    this._form.setOnChange(fn);
  }

  registerOnTouched(fn: () => void): void {
    this._form.setOnTouched(fn);
  }

  setDisabledState(isDisabled: boolean): void {
    this._form.setDisabledByForm(isDisabled);
  }
}

import { InjectionToken, Signal } from '@angular/core';

export type RadioSize = 'sm' | 'default' | 'lg';
export type RadioVariant = 'default' | 'card';
export type RadioColor = 'default' | 'destructive' | 'success';

export type RadioItemRef = {
  readonly value: () => unknown;
  readonly disabled: () => boolean;
  focus(): void;
};

export type RadioGroupContext = {
  readonly name: Signal<string>;
  readonly value: Signal<unknown>;
  readonly disabled: Signal<boolean>;
  readonly required: Signal<boolean>;
  readonly hasError: Signal<boolean>;
  readonly size: Signal<RadioSize>;
  readonly variant: Signal<RadioVariant>;
  readonly color: Signal<RadioColor>;
  readonly loading: Signal<boolean>;
  select(value: unknown): void;
  notifyTouched(): void;
  register(item: RadioItemRef): void;
  unregister(item: RadioItemRef): void;
  focusNext(current: RadioItemRef): void;
  focusPrev(current: RadioItemRef): void;
  isFirstEnabled(item: RadioItemRef): boolean;
};

export const RADIO_GROUP_CTX = new InjectionToken<RadioGroupContext>('RADIO_GROUP_CTX');

import { cva, type VariantProps } from 'class-variance-authority';

export const radioVariants = cva(
  [
    'peer appearance-none shrink-0 rounded-full border bg-background cursor-pointer',
    'transition-all duration-200',
    'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2',
    'disabled:cursor-not-allowed disabled:opacity-50',
  ],
  {
    variants: {
      nSize: {
        sm: 'h-3.5 w-3.5',
        default: 'h-4 w-4',
        lg: 'h-5 w-5',
      },
      nColor: {
        default: 'border-input checked:border-primary focus-visible:ring-ring aria-invalid:border-destructive aria-invalid:ring-destructive',
        destructive: 'border-input checked:border-destructive focus-visible:ring-destructive',
        success: 'border-input checked:border-success focus-visible:ring-success',
      },
    },
    defaultVariants: {
      nSize: 'default',
      nColor: 'default',
    },
  },
);

export type RadioVariants = VariantProps<typeof radioVariants>;

export const radioIndicatorVariants = cva('pointer-events-none absolute inset-0 m-auto rounded-full', {
  variants: {
    nSize: {
      sm: 'h-1.5 w-1.5',
      default: 'h-2 w-2',
      lg: 'h-2.5 w-2.5',
    },
    nColor: {
      default: 'bg-primary',
      destructive: 'bg-destructive',
      success: 'bg-success',
    },
  },
  defaultVariants: {
    nSize: 'default',
    nColor: 'default',
  },
});

export const radioCardVariants = cva(
  [
    'flex items-start gap-3 rounded-lg border bg-background p-4 cursor-pointer',
    'transition-colors hover:bg-accent/40',
    'has-[input:focus-visible]:ring-2 has-[input:focus-visible]:ring-offset-2',
    'has-[input:disabled]:cursor-not-allowed has-[input:disabled]:opacity-50',
  ],
  {
    variants: {
      nColor: {
        default: 'border-input has-[input:checked]:border-primary has-[input:checked]:ring-2 has-[input:checked]:ring-primary/20 has-[input:focus-visible]:ring-ring',
        destructive: 'border-input has-[input:checked]:border-destructive has-[input:checked]:ring-2 has-[input:checked]:ring-destructive/20 has-[input:focus-visible]:ring-destructive',
        success: 'border-input has-[input:checked]:border-success has-[input:checked]:ring-2 has-[input:checked]:ring-success/20 has-[input:focus-visible]:ring-success',
      },
    },
    defaultVariants: {
      nColor: 'default',
    },
  },
);

export { RadioComponent } from './radio.component';
export { RadioGroupComponent } from './radio-group.component';
export {
  RADIO_GROUP_CTX,
  type RadioColor,
  type RadioGroupContext,
  type RadioItemRef,
  type RadioSize,
  type RadioVariant,
} from './radio.tokens';
export {
  radioCardVariants,
  radioIndicatorVariants,
  radioVariants,
  type RadioVariants,
} from './radio.variants';

